const GRID_COLS = 48, GRID_ROWS = 36;
function isOpenAt(sc, xf, yf) {
  const g = OPEN_GRIDS[sc];
  if (!g) return true;
  const c = Math.floor(xf * GRID_COLS);
  const r = Math.floor(yf * GRID_ROWS);
  // exige a célula e vizinhas laterais abertas (evita borda de mata)
  for (let dc = -1; dc <= 1; dc++) {
    const cc = c + dc;
    if (cc < 0 || cc >= GRID_COLS || r < 0 || r >= GRID_ROWS) return false;
    if (g[r][cc] !== "1") return false;
  }
  return true;
}

